Here's an example of a C++ program to transpose a matrix:

#include <iostream>
using namespace std;

const int ROWS = 3;
const int COLS = 3;

int main() {
    int matrix[ROWS][COLS];
    int transpose[COLS][ROWS];

    // Input matrix
    cout << "Enter elements of matrix:" << endl;
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            cin >> matrix[i][j];
        }
    }

    // Transpose matrix
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            transpose[j][i] = matrix[i][j];
        }
    }

    // Display transpose matrix
    cout << "Transpose of matrix:" << endl;
    for (int i = 0; i < COLS; i++) {
        for (int j = 0; j < ROWS; j++) {
            cout << transpose[i][j] << " ";
        }
        cout << endl;
    }

    return 0;
} 

In this program, you would first input the elements of the matrix as usual. Then, you would iterate over the matrix and copy the elements to the transpose matrix in a transposed manner. Finally, you would display the transpose matrix to the user.

